"""
MKT Christ Commentary — Isaiah 40 (31 verses — The Voice in the Wilderness)
Run: python3 scripts/zc-christ-isaiah-40.py
Key decisions:
- v3: DIRECT citation — "A voice crying in the wilderness, prepare the way
  of the LORD" = John the Baptist (Mark 1:3; Matt 3:3; Luke 3:4; John 1:23).
  All four gospels quote this verse as the opening programmatic statement
  about John's ministry
- v5: "The glory of the LORD shall be revealed" — Luke 2:9-10 (glory at
  the nativity), John 1:14 (Word made flesh, we beheld his glory)
- v9: "Behold your God!" — the core gospel announcement; Phil 4:5
  ("The Lord is near"), John 1:29 ("Behold the Lamb of God")
- v10-11: Coming with might / good shepherd — Rev 22:12 (coming with
  reward), John 10:11 (I am the good shepherd)
- v28-31: Waiting on YHWH / eagle wings — the final eschatological hope;
  2 Cor 12:9 (strength in weakness); Phil 4:13 (I can do all things
  through Christ)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys so re-running is safe after manual edits.
    # CHANGE? If isaiah.json schema changes, update merge_comm and ISAIAH dict below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
    #   isaiah.json')); print('Isa 40 v3:',d.get('40',{}).get('3','MISSING')[:80])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


ISAIAH = {
    "40": {
        "1": "<p>\"Comfort, comfort my people, says your God\" — the double imperative of comfort (<em>naḥămû naḥămû</em>) opens Second Isaiah (chapters 40-66) as a deliberate reversal of the judgment oracles that filled chapters 1-39. The exile judgment is past; the consolation begins. Luke 2:25: \"Now there was a man in Jerusalem called Simeon, who was righteous and devout. He was waiting for the consolation of Israel, and the Holy Spirit was on him.\" The <em>paraklēsis</em> (consolation/comfort) that Simeon awaited is the Christ child himself — the double comfort of Isaiah 40:1 is fulfilled in the person who is both comfort-bringer and comforter, the one who gathers all of Second Isaiah's promises into himself. John 14:16: \"I will ask the Father, and he will give you another Advocate (<em>paraklēton</em>).\" The comfort that the Spirit brings in the new covenant age flows from the one who first arrived as the \"consolation of Israel.\"</p>",
        "2": "<p>\"Speak tenderly to Jerusalem, and cry to her that her warfare is ended, that her iniquity is pardoned, that she has received from the LORD's hand double for all her sins\" — the twofold announcement: warfare ended, iniquity pardoned. The \"double\" (<em>kiplayim</em>) paid for Jerusalem's sins is the grammar of substitutionary satisfaction — not that Israel suffered too much, but that the debt has been fully discharged. Isaiah 53:5: \"The punishment that brought us peace was on him, and by his wounds we are healed.\" Colossians 2:14: \"having canceled the charge of our legal indebtedness, which stood against us and condemned us; he has taken it away, nailing it to the cross.\" The \"double for all her sins\" finds its ultimate settlement not in Israel's exile suffering but in Christ's cross — the debt cleared once for all so that the warfare is truly ended (Rom 5:1: \"we have peace with God through our Lord Jesus Christ\").</p>",
        "3": "<p>\"A voice cries: 'In the wilderness prepare the way of the LORD; make straight in the desert a highway for our God'\" — the programmatic text of the entire gospel. All four gospels apply this verse to John the Baptist as the forerunner of Jesus: Matthew 3:3 (\"this is he who was spoken of through the prophet Isaiah\"), Mark 1:3 (opening verse of the gospel), Luke 3:4, John 1:23 (John the Baptist's self-identification: \"I am the voice of one calling in the wilderness, 'Make straight the way for the Lord'\"). The DIRECT fulfillment is unambiguous: Isaiah 40:3 is the OT announcement of John the Baptist's mission, and John the Baptist is the forerunner of Christ. The \"highway for our God\" that Isaiah commands the wilderness to prepare is the road that John cuts through the thicket of first-century Judaism, preparing Israel to receive her Messiah. The arrival at the end of the highway is the arrival of YHWH himself in human flesh.</p>",
        "4": "<p>\"Every valley shall be lifted up, and every mountain and hill be made low; the uneven ground shall become level, and the rough places a plain\" — the geographic transformation for the divine procession: every obstacle removed, every terrain leveled. Luke 3:5 quotes this verse as part of the John-the-Baptist announcement. The leveling of mountains and valleys is both literal (divine power over creation) and social/spiritual: Luke 1:51-53 (Magnificat: he has brought down rulers from their thrones but has lifted up the humble; filled the hungry with good things but sent the rich away empty). The mountains that must be made low are the proud human structures (imperial power, religious establishment) that impede the arrival of the humble King; the valleys that must be lifted up are the despised (tax collectors, sinners, Samaritans) who receive the kingdom first. Christ's ministry literally performs the Isaiah 40:4 topography.</p>",
        "5": "<p>\"And the glory of the LORD shall be revealed, and all flesh shall see it together, for the mouth of the LORD has spoken\" — the universal revelation of divine glory that Isaiah's highway leads to. Luke 2:9: \"An angel of the Lord appeared to them, and the glory of the Lord shone around them.\" Luke 2:30-32: Simeon: \"My eyes have seen your salvation, which you have prepared in the sight of all nations: a light for revelation to the Gentiles, and the glory of your people Israel.\" John 1:14: \"The Word became flesh and made his dwelling among us. We have seen his glory, the glory of the one and only Son.\" The \"all flesh shall see it together\" is initially fulfilled in the incarnation — the glory that was veiled in the holy of holies is now visible in the face of Jesus Christ (2 Cor 4:6). The final fulfillment awaits Revelation 1:7: \"Every eye will see him.\"</p>",
        "6": "<p>\"A voice says, 'Cry!' And I said, 'What shall I cry?' All flesh is grass, and all its beauty is like the flower of the field\" — the command to proclaim, followed by the proclamation's content: human transience. The grass-and-flower metaphor is the OT statement of human mortality and impermanence. 1 Peter 1:24-25 quotes this passage directly: \"For, 'All people are like grass, and all their glory is like the flowers of the field; the grass withers and the flowers fall, but the word of the Lord endures forever.' And this is the word that was preached to you.\" The gospel proclaimed by the apostles is the Isaiah 40 proclamation: yes, all flesh is grass — and the Word became that grass (John 1:14: the Word became flesh), entered human transience, died — and rose, so that the enduring word of God can share its permanence with those who believe. The contrast between mortal flesh and the enduring word is resolved in the incarnation.</p>",
        "7": "<p>\"The grass withers, the flower fades when the breath of the LORD blows on it; surely the people are grass\" — the application of the grass-metaphor to \"the people\" broadly: all humanity is mortal under the breath/wind (<em>rûaḥ</em>) of YHWH. The divine breath that creates (Gen 2:7) and sustains is also the divine breath that withdraws, causing death. John 3:6: \"Flesh gives birth to flesh, but the Spirit gives birth to spirit.\" The flesh that withers when YHWH's <em>rûaḥ</em> blows is reborn when that same Spirit enters it in new creation: Ezekiel 37's valley of dry bones, John 3:5-8 (born of water and Spirit), 2 Corinthians 3:6 (the Spirit gives life). The <em>rûaḥ</em> that kills the grass of fallen humanity is the same Spirit who raises the dead — Christ's resurrection is the firstfruit of the Spirit's life-giving work (Rom 8:11: the Spirit who raised Jesus will also give life to mortal bodies).</p>",
        "8": "<p>\"The grass withers, the flower fades, but the word of our God will stand forever\" — the great contrast: human impermanence vs. divine word's permanence. The word (<em>dābar</em>) of God endures when all flesh does not. John 1:1: \"In the beginning was the Word.\" 1 Peter 1:25: \"the word of the Lord endures forever. And this is the word that was preached to you.\" Matthew 24:35: \"Heaven and earth will pass away, but my words will never pass away.\" The eternal Word of Isaiah 40:8 takes on a new dimension after the prologue of John: the <em>dābar</em> that endures is not merely a divine decree but a divine Person who entered the withering grass of human existence and emerged from the grave with the permanence that the eternal Word always possessed. \"The word stands forever\" because the Word, Jesus Christ, is risen and lives forever (Heb 7:25).</p>",
        "9": "<p>\"Go on up to a high mountain, O Zion, herald of good news; lift up your voice with strength, O Jerusalem, herald of good news; lift it up, fear not; say to the cities of Judah, 'Behold your God!'\" — the commissioning of Zion as the herald (<em>mĕbaśśeret</em>, feminine participle of <em>bāśar</em> = the gospel root word) of good news. The announcement she is sent to proclaim is the three-word summary: \"Behold your God!\" (<em>hinnēh ʾĕlōhêkem</em>). John 1:29: \"The next day John saw Jesus coming toward him and said, 'Look, the Lamb of God, who takes away the sin of the world!'\" John the Baptist performs exactly the Zion-herald role of Isaiah 40:9: pointing to the one arriving and saying \"Behold!\" — \"Look, the Lamb of God.\" Philippians 4:5: \"The Lord is near.\" The \"Behold your God!\" of Isaiah 40:9 is the programmatic announcement that runs through the entire NT: Christ has arrived; God in person has come to his people.</p>",
        "10": "<p>\"Behold, the Lord GOD comes with might, and his arm rules for him; behold, his reward is with him, and his recompense before him\" — the mighty arrival: the arm of YHWH (the divine strength that Isaiah 53:1 will identify with the suffering Servant) comes bearing reward. Revelation 22:12: \"Look, I am coming soon! My reward is with me, and I will give to each person according to what they have done.\" The returning Christ of Revelation 22:12 quotes Isaiah 40:10 as the announcement of his return: the Lord who comes with might, whose reward is with him, is the Christ who returns to render final judgment and redemption. The \"arm\" (<em>zĕrôaʿ</em>) that rules at the first coming through the humble Servant (Isaiah 53) rules openly at the return — might that was concealed at the cross will be manifest at the parousia.</p>",
        "11": "<p>\"He will tend his flock like a shepherd; he will gather the lambs in his arms; he will carry them in his bosom, and gently lead those that are with young\" — the shepherd-image for YHWH's tender care, immediately juxtaposed with the mighty-arm of v10. The paradox is the paradox of Christ: omnipotence and gentleness in the same person. John 10:11: \"I am the good shepherd. The good shepherd lays down his life for the sheep.\" John 10:27-28: \"My sheep listen to my voice; I know them, and they follow me. I give them eternal life.\" Matthew 18:12-14: the shepherd who leaves the ninety-nine to find the one lost sheep. The shepherd who carries lambs in his bosom (Is 40:11) is the same shepherd who carries the lost sheep on his shoulders (Luke 15:5) — the vulnerability of the lamb and the tenderness of the shepherd are both present in Christ who is simultaneously Lamb (John 1:29) and Shepherd (John 10:11).</p>",
        "12": "<p>\"Who has measured the waters in the hollow of his hand and marked off the heavens with a span, enclosed the dust of the earth in a measure and weighed the mountains in scales and the hills in a balance?\" — the rhetorical question series establishing divine incomparability: the creation-scale operations that only YHWH can perform. The measurers of v12 are answered by v28's declaration that YHWH's understanding is unsearchable. Colossians 1:16-17: \"For in him all things were created: things in heaven and on earth, visible and invisible... all things have been created through him and for him. He is before all things, and in him all things hold together.\" The one who \"measured the waters in the hollow of his hand\" is the Word through whom all things were made (John 1:3) — the Christological reading of Isaiah 40:12 places Christ at creation as the divine measuring hand, which is why the Colossian hymn can speak of him holding all things together.</p>",
        "13": "<p>\"Who has measured the Spirit of the LORD, or what man shows him his counsel?\" — the unsearchability of the divine mind and Spirit. No creature has advised YHWH or calibrated his Spirit. Romans 11:34-35: \"'Who has known the mind of the Lord? Or who has been his counselor? Who has ever given to God, that God should repay them?'\" Paul quotes this verse in the doxology at the end of Romans 9-11 to close his exposition of divine election — no human can demand an accounting from God or claim that God owes them counsel. 1 Corinthians 2:16: \"For who has known the mind of the Lord so as to instruct him? But we have the mind of Christ.\" The astonishing reversal in Paul: Isaiah 40:13 asks \"who has known the mind of the LORD?\" as a rhetorical question expecting \"no one\" — but Paul says the Spirit-indwelt community has the mind of Christ. The inaccessible divine mind becomes accessible through Christ.</p>",
        "14": "<p>\"Whom did he consult, and who made him understand? Who taught him the path of justice, and taught him knowledge, and showed him the way of understanding?\" — the continuation of divine self-sufficiency: YHWH's wisdom is not learned from any creature. Job 38-41 explores the same territory in dramatic form. John 5:30: \"By myself I can do nothing; I judge only as I hear, and my judgment is just, for I seek not to please myself but him who sent me.\" The apparent paradox: Isaiah 40:14 affirms that YHWH learned from no one; John 5:30 has Jesus acting only from the Father. The resolution is Trinitarian: within the eternal divine life, the Father and Son are in perfect communion, not hierarchical instruction. The eternal Son who acts only from the Father is not a creature being taught but the co-equal divine person whose wisdom is the Father's wisdom — the same unsearchable wisdom that Isaiah 40:14 attributes to YHWH alone.</p>",
        "15": "<p>\"Behold, the nations are like a drop from a bucket, and are accounted as the dust on the scales; behold, he takes up the coastlands like fine dust\" — the incomparable scale difference between YHWH and the nations: the greatest empires are infinitesimal. The bucket-drop and scale-dust metaphors establish divine transcendence over all human power. Revelation 19:15: \"Coming out of his mouth is a sharp sword with which to strike down the nations. He will rule them with an iron scepter.\" The nations that are dust-on-scales before YHWH are the nations that assemble against Christ at Armageddon — the disproportion is so total that the imagery is almost absurd. Revelation 11:15: \"The kingdom of the world has become the kingdom of our Lord and of his Messiah, and he will reign for ever and ever.\" The bucket-drop nations of Isaiah 40:15 become the worshiping nations of Revelation 15:4 (\"All nations will come and worship before you\") — dust that is gathered into glory through Christ.</p>",
        "16": "<p>\"Lebanon would not suffice for fuel, nor are its animals enough for a burnt offering\" — the inadequacy of the entire creation's resources to constitute a worthy sacrifice for YHWH: Lebanon's famous forests as firewood, all Lebanon's animals as offerings — insufficient. Hebrews 10:4: \"It is impossible for the blood of bulls and goats to take away sins.\" The logic of Isaiah 40:16 runs through all of Hebrews: if Lebanon's animals are not enough to honor YHWH, how can any finite sacrifice atone for sin before an infinite God? The answer is the offering that is infinite: Hebrews 9:12: \"He entered the Most Holy Place once for all by his own blood, thus obtaining eternal redemption.\" The sacrifice that Lebanon cannot supply is supplied by the Lamb who is YHWH's own provision (Gen 22:14, John 1:29: \"Behold the Lamb of God who takes away the sin of the world\").</p>",
        "17": "<p>\"All the nations are as nothing before him, they are accounted by him as less than nothing and emptiness\" — the double negation: not just nothing but \"less than nothing\" (<em>meʾayin</em>). The most powerful human collective is not merely small but ontologically beneath the threshold of significance when measured against YHWH. Philippians 3:8: \"What is more, I consider everything a loss because of the surpassing worth of knowing Christ Jesus my Lord, for whose sake I have lost all things. I consider them garbage.\" Paul's personal application of the Isaiah 40:17 logic to his own credentials: the things that counted as national and religious achievement (Phil 3:4-6) are \"garbage\" (<em>skybala</em>) relative to knowing Christ. The Isaiah 40 framework — all nations as nothing — becomes the framework for understanding why Paul abandoned his Pharisaic status: before the incomparable Christ, all human distinction is Isaiah 40:17's \"less than nothing.\"</p>",
        "18": "<p>\"To whom then will you liken God, or what likeness compare with him?\" — the incomparability challenge that structurally frames the idol polemic (vv18-20) and the creation hymn (vv21-31): you cannot liken YHWH to anything because there is no category that contains him. John 1:18: \"No one has ever seen God, but the one and only Son, who is himself God and is in closest relationship with the Father, has made him known.\" The question \"to whom will you liken God?\" receives a definitive answer only in the incarnation: the God who cannot be likened to any creature becomes a creature (Heb 1:3: \"the exact representation of his being\"). The incomparable one is made comparable — not diminished but voluntarily accessible — in the person of Christ. The idol-polemic that follows (vv19-20) shows what happens when humans answer the incomparability question with wood and metal; the incarnation shows what happens when YHWH answers it himself.</p>",
        "19": "<p>\"An idol! A craftsman casts it, and a goldsmith overlays it with gold and casts for it silver chains\" — the idol-making process: metal and craft, chains of precious metal. The idol is the human answer to the incomparability question of v18 — when humans cannot conceive of a god beyond their reach, they make one within their reach. Romans 1:23: \"They exchanged the glory of the immortal God for images made to look like a mortal human being and birds and animals and reptiles.\" The gold-and-silver chains of the idol's manufacture (Is 40:19) are the chains by which fallen humanity binds itself — the idol that looks impressive is the prison. Christ breaks these chains: Colossians 2:8 warns against being taken \"captive through hollow and deceptive philosophy, which depends on human tradition and the elemental spiritual forces of this world rather than on Christ.\" The elemental forces are the idols of Isaiah 40; their chains are broken by the incomparable one who could not be contained in any human category.</p>",
        "20": "<p>\"He who is too impoverished for an offering chooses wood that will not rot; he seeks out a skillful craftsman to set up an idol that will not move\" — even the poor person's idol: the wood that won't rot as the best a poor man can afford, carved by the best craftsman to ensure stability. The idol's stability (\"will not move\") is ironic — what cannot move cannot help. Psalm 115:4-7: \"Their idols are silver and gold, made by human hands... They have hands, but cannot feel, feet, but cannot walk.\" Revelation 1:17-18: \"Do not be afraid. I am the First and the Last. I am the Living One; I was dead, and now look, I am alive for ever and ever!\" The idol that \"will not move\" is contrasted with the living Christ who moves, acts, returns, judges. The wood that will not rot is contrasted with the resurrection body that cannot perish — the idol's false permanence vs. the true permanence of the risen Lord.</p>",
        "21": "<p>\"Do you not know? Do you not hear? Has it not been told you from the beginning? Have you not understood from the foundations of the earth?\" — the four rhetorical questions address willful ignorance: the knowledge of YHWH's incomparability is available from the foundations of creation. Romans 1:20: \"For since the creation of the world God's invisible qualities — his eternal power and divine nature — have been clearly seen, being understood from what has been made, so that people are without excuse.\" The \"from the foundations of the earth\" of Isaiah 40:21 is Paul's \"since the creation of the world\" in Romans 1:20 — the same testimony, the same willful suppression. The one who makes himself known from creation's foundations enters that creation in Christ (John 1:10: \"He was in the world, and though the world was made through him, the world did not recognize him\"), making the incomprehensible comprehensible and removing the excuse of unknowing.</p>",
        "22": "<p>\"It is he who sits above the circle of the earth, and its inhabitants are like grasshoppers; who stretches out the heavens like a curtain, and spreads them like a tent to dwell in\" — the cosmic imagery of YHWH's throne perspective: the circular earth below, the stretched heavens as a tent. The inhabitants as grasshoppers echoes the spies' report in Numbers 13:33. Hebrews 1:10-12 quotes Psalm 102:25-27 (parallel to Isaiah 40:22): \"In the beginning, Lord, you laid the foundations of the earth, and the heavens are the work of your hands. They will perish, but you remain.\" The one who stretches out the heavens like a tent in Isaiah 40:22 is the Son through whom the Father made the universe (Heb 1:2) and who will roll up the heavens like a garment when they have served their purpose (Heb 1:12). Revelation 21:1: \"Then I saw a new heaven and a new earth, for the first heaven and the first earth had passed away.\"</p>",
        "23": "<p>\"Who brings princes to nothing, and makes the rulers of the earth as emptiness\" — the de-throning of earthly powers: princes and rulers as <em>tohu</em> (emptiness/chaos, the same word as Genesis 1:2's formless void). The world's ruling structures return to formlessness before YHWH. 1 Corinthians 2:6-8: \"We do, however, speak a message of wisdom among the mature, but not the wisdom of this age or of the rulers of this age, who are coming to nothing. None of the rulers of this age understood it, for if they had, they would not have crucified the Lord of glory.\" The rulers who are \"coming to nothing\" in 1 Corinthians 2:6 are the Isaiah 40:23 princes brought to nothing — and their decisive self-disclosure was the crucifixion of the Lord of glory, the act that simultaneously revealed their ignorance and accomplished their defeat (Col 2:15).</p>",
        "24": "<p>\"Scarcely are they planted, scarcely sown, scarcely has their stem taken root in the earth, when he blows on them, and they wither, and the tempest carries them off like stubble\" — the fragility of political power: the swift rise and fall of ruling dynasties. The breath (<em>nāšap</em>) of YHWH that withers empires in Isaiah 40:24 is the same breath of his mouth that strikes down the lawless one in 2 Thessalonians 2:8: \"And then the lawless one will be revealed, whom the Lord Jesus will overthrow with the breath of his mouth and destroy by the splendor of his coming.\" Every empire that appeared invincible has withered; the final empire of the man of lawlessness will wither before the returning Christ — the Isaiah 40:24 pattern applies to every human power arrangement that exalts itself against YHWH, and receives its definitive fulfillment at the parousia.</p>",
        "25": "<p>\"To whom then will you compare me, that I should be like him? says the Holy One\" — the incomparability challenge repeated from v18, now voiced by YHWH in the first person. The Holy One (<em>haqqādôš</em>) asserts his own uniqueness. Hebrews 7:26: \"For it was fitting that we should have such a high priest, holy, innocent, unstained, separated from sinners, and exalted above the heavens.\" Revelation 4:8: \"'Holy, holy, holy is the Lord God Almighty, who was, and is, and is to come.'\" Christ is the Holy One of God (Mark 1:24: the demon's confession), the one to whom Isaiah 40:25 attributes unique incomparability. The resurrection vindicates the incomparability claim: no other claimant to divine status rose from the dead. The incomparable Holy One has made himself comparable — not to idols or princes, but to suffering humanity — and in doing so has made humanity comparable to him (1 John 3:2).</p>",
        "26": "<p>\"Lift up your eyes on high and see: who created these? He who brings out their host by number, calling them all by name; by the greatness of his might and because he is strong in power, not one is missing\" — the starry host as YHWH's army, each named and numbered. The creator-shepherd who knows each star's name is the same shepherd of v11 who knows each lamb. Matthew 10:29-30: \"Are not two sparrows sold for a penny? Yet not one of them will fall to the ground outside your Father's care. And even the very hairs of your head are all numbered.\" John 10:3: \"He calls his own sheep by name and leads them out.\" The star-calling of Isaiah 40:26 (calling them all by name, not one missing) is the type of the good shepherd's sheep-calling (John 10:3) and the Father's sparrow-counting (Matt 10:29) — the same divine attentiveness to the individual that governs both cosmic and personal scales.</p>",
        "27": "<p>\"Why do you say, O Jacob, and speak, O Israel, 'My way is hidden from the LORD, and my right is disregarded by my God'?\" — the complaint of the exilic community: divine hiddenness, divine indifference to justice. The complaint is the pastoral problem that the rest of the chapter addresses. Hebrews 4:15-16: \"For we do not have a high priest who is unable to empathize with our weaknesses, but we have one who has been tempted in every way, just as we are — yet he did not sin. Let us then approach God's throne of grace with confidence.\" The \"my way is hidden from the LORD\" complaint is answered not merely by reassertion of divine knowledge (v28) but by the incarnation: Christ who was \"hidden\" at Gethsemane (\"My God, my God, why have you forsaken me?\" — Ps 22:1) entered the experience of divine abandonment so that no believer need fear that their way is permanently hidden from the Father.</p>",
        "28": "<p>\"Have you not known? Have you not heard? The LORD is the everlasting God, the Creator of the ends of the earth. He does not faint or grow weary; his understanding is unsearchable\" — the answer to v27's complaint: YHWH's character is its own answer. Everlasting, Creator, unfainting, unsearchable in understanding. Romans 11:33: \"Oh, the depth of the riches of the wisdom and knowledge of God! How unsearchable his judgments, and his paths beyond tracing out!\" Paul's doxology at the end of Romans 9-11 echoes Isaiah 40:28: the unsearchable understanding of Isaiah becomes the unsearchable judgments of God in Paul — both declare that the divine wisdom behind the exile (Isaiah) and behind the mystery of election (Romans) exceeds human comprehension but is entirely trustworthy. The \"unsearchable\" of Isaiah 40:28 is the same ground of trust that sustains Paul's confidence in Christ's redemptive plan (Eph 3:8: \"the unsearchable riches of Christ\").</p>",
        "29": "<p>\"He gives power to the faint, and to him who has no might he increases strength\" — the reversal: divine strength flows to human weakness, not human strength. The correlation between human faintness and divine supply is the hinge verse of the passage. 2 Corinthians 12:9-10: \"But he said to me, 'My grace is sufficient for you, for my power is made perfect in weakness.' Therefore I will boast all the more gladly about my weaknesses, so that Christ's power may rest on me. That is why, for Christ's sake, I delight in weaknesses.\" Paul's experience of the Isaiah 40:29 principle is direct and personal: he who has no might has Christ's strength increased in him. Philippians 4:13: \"I can do all this through him who gives me strength.\" The faint who receive power in Isaiah 40:29 are the weakest disciples who receive the Spirit's power at Pentecost (Acts 1:8: \"you will receive power when the Holy Spirit comes on you\").</p>",
        "30": "<p>\"Even youths shall faint and be weary, and young men shall fall exhausted\" — the surprising vulnerability: even the strongest (youths, young men) can exhaust. The cultural expectation is that youth is inexhaustible — Isaiah overturns it. The exhaustion of the strong is the premise for the gift of v31. 1 Corinthians 1:27: \"But God chose the foolish things of the world to shame the wise; God chose the weak things of the world to shame the strong.\" The young men who fall exhausted are the type of every human who discovers that natural strength has limits. The disciples who \"could not stay awake\" in Gethsemane (Matt 26:40-45) enact Isaiah 40:30 — the spirit is willing but the flesh faints. Christ who did not sleep in Gethsemane, who prayed through the night, received strength from the angel (Luke 22:43) — the faithful Servant who did not faint or grow weary (Is 42:4) because the Father's Spirit sustained him (Is 42:1).</p>",
        "31": "<p>\"But they who wait for the LORD shall renew their strength; they shall mount up with wings like eagles; they shall run and not be weary; they shall walk and not faint\" — the climax of Isaiah 40: the exchange of human exhaustion for divine energy through waiting (<em>qāwâh</em>, expectant hope). The three modes of renewed motion — soaring, running, walking — represent different stages of the Spirit-empowered life. Romans 8:11: \"And if the Spirit of him who raised Jesus from the dead is living in you, he who raised Christ from the dead will also give life to your mortal bodies because of his Spirit who lives in you.\" The eagle-soaring of Isaiah 40:31 is the resurrection life given to mortal bodies through the Spirit. Acts 1:8: the disciples who \"wait\" (<em>qāwâh's NT equivalent: perimenontes</em>) for the Spirit in Jerusalem (Acts 1:4) receive the power to go to the ends of the earth — the waiting that receives strength. 2 Corinthians 4:16: \"Though outwardly we are wasting away, yet inwardly we are being renewed day by day\" — Isaiah 40:31 enacted in daily experience through Christ.</p>"
    }
}


def main():
    existing = load_comm("mkt-christ", "isaiah")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, ISAIAH)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "isaiah", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("3", "Baptist"), ("9", "Behold"), ("11", "shepherd"), ("31", "eagle")]:
        entry = existing.get("40", {}).get(v, "MISSING")
        print(f"  Isa 40:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    ch = existing.get("40", {})
    missing = [str(i) for i in range(1, 32) if str(i) not in ch]
    print(f"  Missing verses: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
